parameters.text:
={{ $json.data.length > 0 ? 
  "📂 *Tus solicitudes registradas:*\n\n" + 
  $json.data.map(ticket => 
    "🎫 *ID:* " + ticket.ID_ticket + 
    "\n📝 *Tipo:* " + ticket.tipo + 
    "\n⏳ *Estado:* " + ticket.estado + 
    "\n-------------------"
  ).join('\n') : 
  "Aún no tienes solicitudes registradas. 🤷‍♂️" 
}}
